    var g = ctx.createRadialGradient(cx, cy, 6, cx, cy, S * 0.5);
    g.addColorStop(0, 'rgba(6,5,4,0.96)');
    g.addColorStop(0.45, 'rgba(14,11,9,0.9)');
    g.addColorStop(0.72, 'rgba(30,22,16,0.55)');
